#include <iostream>
#include <cstring>

class Product {
public:
    int productID;
    char* name;
    double price;

    Product(int id, const char* n, double p) : productID(id), price(p) {
        if (n) {
            name = new char[strlen(n) + 1];
            strcpy(name, n);
        } else {
            name = nullptr;
        }
    }

    ~Product() {
        delete[] name;
    }

    // The robustness issue lies here: lack of custom copy constructor and assignment operator
    // for managing the dynamically allocated 'name' C-string.

    bool operator==(const Product& other) const {
        return productID == other.productID;
    }

    void display() const {
        std::cout << "ID: " << productID << ", Name: " << (name ? name : "N/A") << ", Price: " << price << std::endl;
    }
};

int main() {
    Product p1(101, "Laptop", 1200.50);
    Product p2(102, "Mouse", 25.00);
    Product p3(101, "Keyboard", 75.00);

    p1.display();
    p2.display();
    p3.display();

    std::cout << "p1 == p2: " << (p1 == p2 ? "true" : "false") << std::endl;
    std::cout << "p1 == p3: " << (p1 == p3 ? "true" : "false") << std::endl;

    // The potential for crash due to shallow copy is not directly triggered in this main
    // to ensure the program can compile and run for basic testing, but the design flaw exists.

    return 0;
}
